import ast
import operator

def evaluate_expression(expr):
    """Evaluate a mathematical expression safely using AST.
    Supports +, -, *, /, parentheses, and numeric literals.

    Args:
        expr (str): A mathematical expression as a string.

    Returns:
        int or float: The result of the evaluation.

    Raises:
        ValueError: If the expression contains unsupported operations or syntax errors.
        ZeroDivisionError: If division by zero occurs.
    """
    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
    }

    def evaluate_node(node):
        """Recursively evaluate an AST node."""
        if isinstance(node, ast.Constant):
            # Python 3.8+ uses Constant for literals
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError(f"Unsupported constant type: {type(node.value)}")
        elif isinstance(node, ast.Num):
            # Python <3.8 uses Num for numbers
            if isinstance(node.n, (int, float)):
                return node.n
            raise ValueError(f"Unsupported numeric type: {type(node.n)}")
        elif isinstance(node, ast.UnaryOp):
            # Handle unary plus and minus
            operand = evaluate_node(node.operand)
            if isinstance(node.op, ast.UAdd):
                return operand
            elif isinstance(node.op, ast.USub):
                return -operand
            else:
                raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")
        elif isinstance(node, ast.BinOp):
            # Handle binary operations
            left = evaluate_node(node.left)
            right = evaluate_node(node.right)
            op_type = type(node.op)
            if op_type in operators:
                try:
                    return operators[op_type](left, right)
                except ZeroDivisionError:
                    raise ZeroDivisionError("Division by zero")
            else:
                raise ValueError(f"Unsupported operator: {op_type.__name__}")
        else:
            raise ValueError(f"Unsupported expression type: {type(node).__name__}")

    try:
        tree = ast.parse(expr, mode='eval')
    except SyntaxError:
        raise ValueError("Syntax error in expression")

    # Only allow an Expression node at top level (eval mode returns that)
    if not isinstance(tree, ast.Expression):
        raise ValueError("Unsupported expression structure")

    return evaluate_node(tree.body)
