The bug is that the `deep` merge strategy performs a shallow merge instead of recursively merging nested dictionaries. The fix implements a recursive merge function that creates a new dict without mutating the base.

```python
def merge_configs(base, override, merge_strategy="deep"):
    """Merge override into base config.

    If merge_strategy is 'shallow', performs a shallow merge.
    If merge_strategy is 'deep', recursively merges nested dicts.
    """
    def deep_merge(a, b):
        """Recursively merge dict b into dict a without modifying a."""
        result = a.copy()
        for key, b_val in b.items():
            if key in result and isinstance(result[key], dict) and isinstance(b_val, dict):
                result[key] = deep_merge(result[key], b_val)
            else:
                result[key] = b_val
        return result

    if merge_strategy == "shallow":
        return {**base, **override}
    return deep_merge(base, override)
