def parse_entry(line):
    # Validate input type
    if not isinstance(line, str):
        return None

    # Must contain exactly one colon
    if ':' not in line:
        return None

    key, sep, value = line.partition(':')
    key = key.strip()
    value = value.strip()

    # Key and value must be non-empty
    if not key or not value:
        return None

    # Try to convert value to int, then float, otherwise keep as string
    try:
        converted = int(value)
    except ValueError:
        try:
            converted = float(value)
        except ValueError:
            converted = value

    return (key, converted)
